--
-- Name: pg_find_index(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.pg_find_index(tabl text, col text) RETURNS SETOF name
    LANGUAGE plpgsql
    AS $_$

BEGIN
RETURN QUERY EXECUTE

'
select
    i.relname as index_name
from
    pg_class t,
    pg_class i,
    pg_index ix,
    pg_attribute a
where
    t.oid = ix.indrelid
    and i.oid = ix.indexrelid
    and a.attrelid = t.oid
    and a.attnum = ANY(ix.indkey)
    and t.relkind = ''r''
    and t.relname = $1
    and a.attname = $2
' USING tabl, col;
RETURN;
END;

$_$;


--
-- Name: strip_tags(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.strip_tags(text) RETURNS text
    LANGUAGE sql
    AS $_$
    SELECT regexp_replace(
        regexp_replace($1,
           E'<[^>]*?(\s* href \s* = \s* ([\'"]) ([^>]*?) ([\'"]) ) [^>]*?>',
           E' (\\3) ',
            'gx'),
        E'(< [^>]*? >)',
        E'',
         'gx')
$_$;


--
-- Name: trigger_tytul_sort(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trigger_tytul_sort() RETURNS trigger
    LANGUAGE plpython3u
    AS $$
    if TD["new"]["tytul_oryginalny_sort"]:
      # Jeżeli jest coś w tym polu, to sprawdź, może nie warto go zmieniać
      # jeżeli nie, to uzupełnij je.
      if TD["event"] == "UPDATE":
          if TD["new"]["tytul_oryginalny"] == TD["old"]["tytul_oryginalny"]:
              if TD["new"].get("jezyk_id") == TD["old"].get("jezyk_id"):
                return

    version = "get_tytul_sort_ver_6_initialized"
    cache = version + "_cache"

    jezyk_id = TD["new"].get("jezyk_id", None)

    if jezyk_id is not None:
        # ma jezyk_id

        if GD.get(cache) is None:
            # utwórz słownik CACHE
            GD[cache] = {}

        if GD[cache].get(jezyk_id) is None:
            query = "SELECT skrot FROM bpp_jezyk WHERE id = %s" % TD["new"]["jezyk_id"]
            res = plpy.execute(query)
            GD[cache][jezyk_id] = res[0]["skrot"]

        jezyk = GD[cache].get(jezyk_id)

    else:
        jezyk = "pol."


    tytul_oryginalny = TD["new"]["tytul_oryginalny"]

    if not GD.get(version, None):
      GD[version] = {
        'ang.': ["the ", "a "],
        'niem.': ["der ", "die ", "das ", ],
        'fr.': ["la ", "le ", "en "],
        'wł.': ["la ", "en "],
        'hiszp.': ["de ", "la ", "en "]
      }

    replaces = GD.get(version).get(jezyk, [" ", "\t"])

#    if jezyk not in ['ang.', 'pol.']:
#        raise Exception("%r %r %r" % (GD[cache], replaces, jezyk))

    ret = tytul_oryginalny.lower().strip()

    for elem in replaces:
      while True:
        if ret.startswith(elem):
          ret = ret[len(elem):]
          continue
        break

    ret = ret.replace("'", "").replace('"', '')

    #if "test" in ret:
    #     raise Exception("%s.. %s.. %s.. %s.. %s.." % (GD[cache], replaces, jezyk, TD['new']['tytul_oryginalny'], ret))

    TD["new"]["tytul_oryginalny_sort"] = ret

    return "modify"
$$;


--
-- Name: ts_post_bpp_autor_search(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ts_post_bpp_autor_search() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
  DECLARE
    v TEXT;

  BEGIN
    v :=
      COALESCE(NEW.nazwisko, '') || ' ' ||
      COALESCE(NEW.imiona, '') || ' ' ||
      COALESCE(NEW.poprzednie_nazwiska, '');

    NEW.search := to_tsvector('bpp_nazwy_wlasne', v);

    RETURN NEW;
  END;

  $$;


--
-- Name: ts_post_bpp_jednostka_search(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ts_post_bpp_jednostka_search() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
  DECLARE
    v TEXT;

  BEGIN

    IF NEW.widoczna = FALSE THEN
      NEW.search := NULL;
      RETURN NEW;
    END IF;

    v :=
      COALESCE(NEW.nazwa, '') || ' ' ||
      COALESCE(NEW.opis, '');

    NEW.search := to_tsvector('bpp_nazwy_wlasne', v);

    RETURN NEW;
  END;

  $$;


