--
-- Name: zaznacz_cache_liczba_n_last_updated_wymaga_przeliczenia_trigger(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.zaznacz_cache_liczba_n_last_updated_wymaga_przeliczenia_trigger() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN

    INSERT INTO bpp_cache_liczba_n_last_updated(id, wymaga_przeliczenia)
    VALUES (1, true)
    ON CONFLICT (id)
        DO UPDATE SET wymaga_przeliczenia = true;

    RETURN NULL; -- result is ignored since this is an AFTER trigger
END;
$$;


