1	opis_bibliograficzny.html	{% load prace %}\n\n{# *********** #}\n{# TYTUŁ PRACY #}\n{# *********** #}\n\n{% if praca.tytul %}\n    <b>{{ praca.tytul_oryginalny|safe }} ({{ praca.tytul|safe }}).</b>\n{% else %}\n    <b>{{ praca.tytul_oryginalny|znak_na_koncu:"."|safe }}</b>\n{% endif %}\n{% if praca.charakter_formalny.charakter_ogolny != 'roz' %}\n    {{ praca.oznaczenie_wydania|default:""|znak_na_koncu:"." }}\n{% endif %}\n\n{# ******* #}\n{# AUTORZY #}\n{# ******* #}\n\n    {{ praca.tekst_przed_pierwszym_autorem|default:"" }}\n    {% for autor in praca.autorzy_dla_opisu %}{% ifchanged autor.typ_odpowiedzialnosci %}[{{ autor.typ_odpowiedzialnosci.skrot|upper }}] {% endifchanged %}{% if links == "admin" %}<a href="{% url "admin:bpp_autor_change" autor.autor.pk %}">{% else %}{% if links == "normal" %}<a href="{% url "bpp:browse_autor" autor.autor.slug %}">{% else %}{% endif %}{% endif %}{% if links %}{{ autor.zapisany_jako }}{% else %}{{ autor.zapisany_jako|upper }}{% endif %}{% if links == "admin" or links == "normal" %}</a>{% endif %}{% if not forloop.last %}, {% else %}{{ praca.tekst_po_ostatnim_autorze|default:"" }}. {% endif %}{% endfor %}\n\n{# ****** #}\n{# ZRÓDŁO #}\n{# ****** #}\n\n{% if praca.zrodlo %}\n    <i>{{ praca.zrodlo.skrot }}</i> {{ praca.informacje|default:""|safe }}\n{% else %}\n    {% if praca.informacje %}\n        {{ praca.informacje|default:""|znak_na_poczatku:" W: "|safe }}\n    {% else %}\n        {% if praca.wydawnictwo_nadrzedne.tytul_oryginalny %}\n            W: {{ praca.wydawnictwo_nadrzedne.tytul_oryginalny }}.\n        {% elif praca.wydawnictwo_nadrzedne_w_pbn.title %}\n            W: {{ praca.wydawnictwo_nadrzedne_w_pbn.title }}.\n        {% endif %}\n    {% endif %}\n{% endif %}\n\n{# ***************** #}\n{# EKSTRA INFORMACJE #}\n{# ***************** #}\n\n{% if praca.charakter_formalny.charakter_ogolny == 'roz' or praca.charakter_formalny.charakter_ogolny == 'ksi' %}\n    {# rozdział lub książka #}\n    {# szczególy i uwagi na końcu #}\n    {{ praca.miejsce_i_rok|default:"" }}\n    {{ praca.wydawnictwo|default:""|znak_na_poczatku:"," }}\n    {{ praca.szczegoly|default:""|znak_na_poczatku:","|safe }}\n    {% if praca.charakter_formalny.charakter_ogolny == 'roz' %}{{ praca.oznaczenie_wydania|default:""|znak_na_koncu:"." }}{% endif %}\n    {{ praca.uwagi|default:""|znak_na_poczatku:","|safe }}\n    {{ praca.isbn|default:""|znak_na_poczatku:"," }}\n    {{ praca.doi|default:""|znak_na_poczatku:". DOI: "|default:". " }}\n{% else %}\n    {# szczegóły i uwagi na poczatku #}\n    {{ praca.szczegoly|default:""|znak_na_poczatku:" "|safe }}\n    {{ praca.uwagi|default:""|znak_na_poczatku:","|safe }}\n    {{ praca.miejsce_i_rok|default:""|znak_na_poczatku:"." }}\n    {{ praca.wydawnictwo|default:""|znak_na_poczatku:"," }}\n    {{ praca.isbn|default:""|znak_na_poczatku:"," }}\n    {{ praca.doi|default:""|znak_na_poczatku:". DOI: "|default:". " }}\n{% endif %}\n\n{# XXX: DO ZROBIENIA: seria wydawnicza -- czy jest w ogóle wyświetlana? #}\n	2000-01-01 00:00:00+00	2000-01-01 00:00:00+00
2	browse/praca_tabela.html	{% load prace user_in_group %}\n<table width="{{ width|default:"100%" }}"\n       class="szczegolyRekordu {{ htmlclass|default:"naglowki_z_lewej" }}">\n    <tr>\n        <th width="20%">Tytuł:</th>\n        <td>\n            {% if praca.tytul %}\n                <b>{{ praca.tytul_oryginalny|safe }} ({{ praca.tytul|safe }}).</b>\n            {% else %}\n                <b>{{ praca.tytul_oryginalny|znak_na_koncu:"."|safe }}</b>\n            {% endif %}\n            {% if praca.charakter_formalny.charakter_ogolny != 'roz' %}\n                {{ praca.oznaczenie_wydania|default:""|znak_na_koncu:"." }}\n            {% endif %}\n        </td>\n    </tr>\n    <tr>\n        <th>\n            Autorzy:\n        </th>\n        <td>\n            {{ praca.tekst_przed_pierwszym_autorem|default:"" }}\n            {% for autor in praca.autorzy_dla_opisu %}{% ifchanged autor.typ_odpowiedzialnosci %}\n                [{{ autor.typ_odpowiedzialnosci.skrot|upper }}] {% endifchanged %}{% if links == "admin" %}\n                <a href="{% url "admin:bpp_autor_change" autor.autor.pk %}">\n                {% else %}{% if links == "normal" %}<a href="{% url "bpp:browse_autor" autor.autor.slug %}">{% else %}\n                {% endif %}{% endif %}{% if links %}{{ autor.zapisany_jako }}{% else %}\n                {{ autor.zapisany_jako|upper }}{% endif %}{% if links == "admin" or links == "normal" %}</a>{% endif %}\n                {% if not forloop.last %}, {% else %}{{ praca.tekst_po_ostatnim_autorze|default:"" }}.\n                {% endif %}{% endfor %}\n        </td>\n    </tr>\n    {% if praca.zrodlo or praca.wydawnictwo_nadrzedne or praca.informacje or praca.szczegoly %}\n        <tr>\n            <th>\n                Szczegóły:\n            </th>\n            <td>\n                {% if praca.zrodlo %}\n                    {% if links == "admin" %}\n                        <a href="{% url "admin:bpp_zrodlo_change" praca.zrodlo.pk %}">{{ praca.zrodlo }}</a>\n                    {% else %}\n                        <a href="{% url "bpp:browse_zrodlo" praca.zrodlo.slug %}">{{ praca.zrodlo }}</a>\n                    {% endif %}\n                {% endif %}\n                {% if praca.wydawnictwo_nadrzedne %}\n                    <a href="{% url "bpp:browse_praca" "wydawnictwo_zwarte" praca.wydawnictwo_nadrzedne.pk %}">\n                {% endif %}\n                {% if not praca.informacje and not praca.szczegoly %}\n                    {% if praca.wydawnictwo_nadrzedne.opis_bibliograficzny %}\n                        W: {{ praca.wydawnictwo_nadrzedne.opis_bibliograficzny|safe }}\n                    {% endif %}\n                {% endif %}\n                {{ praca.informacje|default:""|znak_na_koncu:", "|safe }}\n                {{ praca.szczegoly|default:""|safe }}\n                {% if praca.wydawnictwo_nadrzedne %}\n                    </a>\n                {% endif %}\n            </td>\n        </tr>\n    {% endif %}\n\n    {% if praca.wydawca or praca.wydawca_opis %}\n        <tr>\n            <th>Wydawca:</th>\n            <td>{{ praca.wydawca|default:"" }} {{ praca.wydawca_opis|default:"" }}</td>\n        </tr>\n    {% endif %}\n\n    {% if praca.streszczenia.exists %}\n        <tr>\n            <th>Streszczenie:</th>\n            <td>{% for streszczenie in praca.streszczenia.all %}\n                <!-- <strong>{{streszczenie.jezyk_streszczenia.nazwa}}</strong> -->\n                <p>{{ streszczenie.streszczenie|safe }}</p>\n            {% endfor %}\n            </td>\n        </tr>\n    {% endif %}\n\n    {% if praca.isbn %}\n        <tr>\n            <th>ISBN:</th>\n            <td>{{ praca.isbn }}</td>\n        </tr>\n    {% endif %}\n    {% if praca.e_isbn %}\n        <tr>\n            <th>e-ISBN:</th>\n            <td>{{ praca.e_isbn }}</td>\n        </tr>\n    {% endif %}\n\n    {% if praca.issn %}\n        <tr>\n            <th>ISSN:</th>\n            <td>{{ praca.issn }}</td>\n        </tr>\n    {% endif %}\n    {% if praca.e_issn %}\n        <tr>\n            <th>e-ISSN:</th>\n            <td>{{ praca.e_issn }}</td>\n        </tr>\n    {% endif %}\n\n    {% if praca.charakter_formalny.skrot == "PAT" %}\n        <tr>\n            <th>Patent:</th>\n            <td>\n                <b>- numer zgłoszenia:</b> {{ praca.numer_zgloszenia|default:"brak" }}. <br/>\n                <b>- wydział:</b> {{ praca.wydzial|default:"brak" }}<br/>\n                <b>- rodzaj prawa:</b> {{ praca.rodzaj_prawa|default:"brak" }}<br/>\n                <b>- data zgłoszenia:</b> {{ praca.data_zgloszenia|default:"brak" }}<br/>\n                <b>- numer zgłoszenia:</b> {{ praca.numer_zgloszenia|default:"brak" }}<br/>\n                <b>- data decyzji:</b> {{ praca.data_decyzji|default:"brak" }}<br/>\n                <b>- numer prawa wyłącznego:</b> {{ praca.numer_prawa_wylacznego|default:"brak" }}<br/>\n                <b>- wdrożenie:</b> {% if praca.wdrozenie %}tak{% else %}nie{% endif %}\n            </td>\n        </tr>\n    {% endif %}\n    {% if praca.public_www or praca.www %}\n        <tr>\n            <th>\n                Strona WWW:\n            </th>\n            <td>\n                {% if praca.public_www %}\n                    <a href="{{ praca.public_www }}">\n                        {{ praca.public_www|truncatechars:120 }}</a>\n                {% elif praca.www %}\n                    <a href="{{ praca.www }}">{{ praca.www|truncatechars:120 }}</a>\n                {% else %}\n                    Brak danych\n                {% endif %}\n            </td>\n        </tr>\n    {% endif %}\n    {% if praca.doi %}\n        <tr>\n            <th>DOI</th>\n            <td><a target="_blank" href="http://doi.org/{{ praca.doi }}">{{ praca.doi }}</a></td>\n        </tr>\n    {% endif %}\n\n    {% if praca.pubmed_id %}\n        <tr>\n            <th>PubMed ID:</th>\n            <td><a target="_blank"\n                   href="https://www.ncbi.nlm.nih.gov/pubmed/{{ praca.pubmed_id }}">{{ praca.pubmed_id }}</a></td>\n        </tr>\n    {% endif %}\n\n    {% if praca.pmc_id %}\n        <tr>\n            <th>PMC ID:</th>\n            <td><a href="https://www.ncbi.nlm.nih.gov/pmc/{{ praca.pmc_id }}">{{ praca.pmc_id }}</a></td>\n        </tr>\n    {% endif %}\n\n    <tr>\n        <th>\n            BPP ID:\n        </th>\n        <td>\n            {{ rekord.pk }} <small>czyli {{ rekord.describe_content_type }} o ID = {{ praca.pk }}</small>\n        </td>\n    </tr>\n    <tr>\n        <th>\n            BibTeX:\n        </th>\n        <td>\n            <button id="bibtex-toggle-btn" class="button secondary" type="button">\n                📋 Pokaż BibTeX\n            </button>\n            <button id="bibtex-copy-btn" class="button success" type="button" style="margin-left: 10px; display: none;">\n                📄 Skopiuj do schowka\n            </button>\n            <span id="bibtex-copy-feedback" style="margin-left: 10px;">\n                ✓ Skopiowane!\n            </span>\n            <div id="bibtex-container" style="display: none;">\n                <textarea id="bibtex-content" readonly></textarea>\n            </div>\n        </td>\n    </tr>\n    {% if praca.pbn_uid_id %}\n        <tr>\n            <th>PBN UID:</th>\n            <td>\n                <button class="button secondary"\n                        type="button"\n                        data-open-url="{{ praca.link_do_pbn }}" data-target="_blank">\n                    🔗 {{ praca.pbn_uid_id }}\n                </button>\n                {% if not request.user.is_anonymous and praca.link_do_pi %}\n                    <button class="button secondary"\n                            type="button"\n                            data-open-url="{{ praca.link_do_pi }}" data-target="_blank"\n                            style="margin-left: 10px;">\n                        🏢 Profil instytucji\n                    </button>\n                {% endif %}\n            </td>\n        </tr>\n    {% endif %}\n    {% if praca.pbn_id %}\n        <tr>\n            <th>\n                PBN ID (historyczne):\n            </th>\n            <td>\n                {{ praca.pbn_id }}\n            </td>\n        </tr>\n    {% endif %}\n\n    <tr>\n        <th>\n            Rok:\n        </th>\n        <td>\n            {{ praca.rok }}\n        </td>\n    </tr>\n    <tr>\n        <th>\n            Charakter formalny:\n        </th>\n        <td>\n            {{ praca.charakter_formalny }}\n        </td>\n    </tr>\n\n    <tr>\n        <th>\n            Język:\n        </th>\n        <td>\n            {{ praca.jezyk }}\n        </td>\n    </tr>\n    {% if praca.typ_kbn %}\n        <tr>\n            <th>\n                Typ MNiSW/MEiN:\n            </th>\n            <td>\n                {{ praca.typ_kbn }}\n            </td>\n        </tr>\n    {% endif %}\n    {% if praca.openaccess_tryb_dostepu or praca.openaccess_wersja_tekstu or praca.openaccess_licencja or praca.openaccess_czas_publikacji or praca.openaccess_ilosc_miesiecy %}\n        <tr>\n            <th style="vertical-align: top;">OpenAccess:</th>\n            <td>\n                {% if praca.openaccess_tryb_dostepu %}\n                    <b>- tryb dostępu: </b>\n                    {{ praca.openaccess_tryb_dostepu|lower }}\n                    <br/>\n                {% endif %}\n\n                {% if praca.openaccess_wersja_tekstu %}\n\n                    <b> - wersja tekstu: </b>\n                    {{ praca.openaccess_wersja_tekstu|lower }}<br/>\n\n                {% endif %}\n                {% if praca.openaccess_licencja %}\n\n                    <b> - licencja: </b>\n                    {% if praca.openaccess_licencja.webname %}\n                        <a target="_blank"\n                           href="https://creativecommons.org/licenses/{{ praca.openaccess_licencja.webname }}/3.0/pl/#content">\n                    {% endif %}\n                {{ praca.openaccess_licencja }}\n                {% if praca.openaccess_licencja.webname %}\n                    </a>\n                {% endif %}\n                    <br/>\n\n                {% endif %}\n                {% if praca.openaccess_czas_publikacji %}\n\n                    <b> - czas udostępnienia: </b>\n                    {{ praca.openaccess_czas_publikacji|lower }}<br/>\n\n                {% endif %}\n                {% if praca.openaccess_ilosc_miesiecy %}\n\n                    <b> - ilość miesięcy: </b>\n                    {{ praca.openaccess_ilosc_miesiecy }}\n                    <small>ilość miesięcy które upłynęły od momentu opublikowania do momentu udostępnienia\n                    </small>\n                    <br/>\n\n                {% endif %}\n            </td>\n            </td>\n        </tr>\n    {% endif %}\n    <tr>\n        <th>\n            Punkty MNiSW/MEiN:\n        </th>\n        <td>\n            {{ praca.punkty_kbn }}\n        </td>\n    </tr>\n\n    <tr>\n        <th>\n            Impact factor:\n        </th>\n        <td>\n            {{ praca.impact_factor }}\n        </td>\n    </tr>\n    {% if praca.kwartyl_w_scopus %}\n        <tr>\n            <th>\n                Kwartyl w SCOPUS:\n            </th>\n            <td>\n                Q{{ praca.kwartyl_w_scopus }}\n            </td>\n        </tr>\n    {% endif %}\n    {% if praca.kwartyl_w_wos %}\n        <tr>\n            <th>\n                Kwartyl w WoS:\n            </th>\n            <td>\n                Q{{ praca.kwartyl_w_wos }}\n            </td>\n        </tr>\n    {% endif %}\n    {% if praca.liczba_cytowan %}\n        <tr>\n            <th>Liczba cytowań:</th>\n            <td>{{ praca.liczba_cytowan }}</td>\n        </tr>\n    {% endif %}\n    {% if praca.liczba_znakow_wydawniczych %}\n        <tr>\n            <th>Liczba arkuszy wydawniczych:</th>\n            <td>{{ praca.wymiar_wydawniczy_w_arkuszach }}</td>\n        </tr>\n    {% endif %}\n    {% if uczelnia.pokazuj_punktacja_snip %}\n        <tr>\n            <th>Punktacja SNIP:</th>\n            <td>{{ praca.punktacja_snip }}</td>\n        </tr>\n    {% endif %}\n    {% if uczelnia.pokazuj_index_copernicus %}\n        <tr>\n            <th>\n                Index Copernicus:\n            </th>\n            <td>\n                {{ praca.index_copernicus }}\n            </td>\n        </tr>\n    {% endif %}\n\n    {% if uczelnia.pokazuj_punktacje_wewnetrzna %}\n        <tr>\n            <th>\n                Punktacja wewnętrzna:\n            </th>\n            <td>\n                {{ praca.punktacja_wewnetrzna }}\n            </td>\n        </tr>\n    {% endif %}\n    {% if uczelnia.pokazuj_status_korekty == "always" or uczelnia.pokazuj_status_korekty == "logged-in" and not request.user.is_anonymous %}\n        <tr>\n            <th>\n                Status:\n            </th>\n            <td>\n                {{ praca.status_korekty }}\n            </td>\n        </tr>\n    {% endif %}\n    {% if praca.wydawnictwa_powiazane_set.exists %}\n        <tr>\n            <th>Rekordy powiązane</th>\n            <td>\n                <ol>\n                    {% for elem in praca.wydawnictwa_powiazane_posortowane.all %}\n                        <li>\n                            <a href="{% url "bpp:browse_praca" "wydawnictwo_zwarte" elem.pk %}">{{ elem.opis_bibliograficzny_cache|safe }}</a>\n                        </li>\n                    {% endfor %}\n                </ol>\n            </td>\n        </tr>\n    {% endif %}\n    {% if uczelnia.pokazuj_praca_recenzowana == "always" or uczelnia.pokazuj_praca_recenzowana == "logged-in" and not request.user.is_anonymous %}\n        <tr>\n            <th>\n                Praca recenzowana:\n            </th>\n            <td>\n                {{ praca.recenzowana|yesno }}\n            </td>\n        </tr>\n    {% endif %}\n    {% if praca.ma_procenty %}\n        <tr>\n            <th>Odpowiedzialność za powstanie pracy</th>\n            <td>\n                {% for autor in praca.autorzy_set.all %}\n                    {% if autor.procent %}\n                        {{ autor.procent }}% {{ autor.zapisany_jako }}<br/>\n                    {% endif %}\n                {% endfor %}\n\n            </td>\n        </tr>\n    {% endif %}\n\n    <tr>\n        <th>\n            Rekord utworzony:\n        </th>\n        <td>\n            {{ praca.utworzono }}\n        </td>\n    </tr>\n\n    <tr>\n        <th>\n            Rekord zaktualizowany:\n        </th>\n        <td>\n            {{ praca.ostatnio_zmieniony }}\n        </td>\n    </tr>\n    {% if praca.zewnetrzna_baza_danych.exists %}\n        <tr>\n            <th>Zewnętrzna<br/>baza danych:</th>\n            <td>\n                <ul>{% for db in praca.zewnetrzna_baza_danych.all %}\n                    <li>{{ db.baza.nazwa }}</li>\n                {% endfor %}\n                </ul>\n            </td>\n        </tr>\n    {% endif %}\n</table>\n\n{% if rekord.ma_punktacje_sloty %}\n    {% if uczelnia.pokazuj_tabele_slotow_na_stronie_rekordu == "always" or uczelnia.pokazuj_tabele_slotow_na_stronie_rekordu == "logged-in" and not request.user.is_anonymous %}\n        <h4>Punkty i sloty autorów\n            {% if uczelnia.drukuj_oswiadczenia %}\n                {% if request.user.is_superuser or request.user|has_group:"wprowadzanie danych" %}\n                    <a target="_blank" href="{% url "oswiadczenia:wiele-oswiadczen" rekord.id.0 rekord.id.1 %}">\n                        <span class="fi-print"></span>\n                    </a>\n                {% endif %}\n            {% endif %}\n\n        </h4>\n        <table>\n            <tr>\n                <th>Autor</th>\n                <th>Dyscyplina</th>\n                <th>PkD / PkDAut</th>\n                <th>Slot</th>\n                {% if uczelnia.drukuj_oswiadczenia %}\n                    {% if request.user.is_superuser or request.user|has_group:"wprowadzanie danych" %}\n                        <th>Oświadczenia</th>\n                    {% endif %}\n                {% endif %}\n            </tr>\n\n            {% for pa in rekord.punktacja_autora.select_related %}\n                <tr>\n                    <td>{{ pa.autor }}</td>\n                    <td>{{ pa.dyscyplina.nazwa }}</td>\n                    <td>{{ pa.pkdaut }}</td>\n                    <td>{{ pa.slot }}</td>\n                    {% if uczelnia.drukuj_oswiadczenia %}\n                        {% if request.user.is_superuser or request.user|has_group:"wprowadzanie danych" %}\n                            <td>\n                                <!-- wydruk oswiadczenia -->\n                                <a target="_blank"\n                                   title="Wydruk dyscypliny zgłoszonej dla publikacji"\n                                   href="{% url "oswiadczenia:jedno-oswiadczenie" rekord.id.0 rekord.id.1 pa.autor.id pa.dyscyplina.id %}">\n                                    <span class="fi-print"></span>\n                                </a>\n                                <!-- wydruk drugiego oswiadczenia jezeli ma subdyscypline -->\n                                {% if pa.czy_autor_ma_alternatywna_dyscypline and uczelnia.drukuj_alternatywne_oswiadczenia %}\n                                    &nbsp;\n                                    <a target="_blank"\n                                       title="Wydruk alternatywnej dyscypliny autora (innej, niż zgłoszona dla publikacji)"\n                                       href="{% url "oswiadczenia:jedno-oswiadczenie-druga-dyscyplina" rekord.id.0 rekord.id.1 pa.autor.id pa.dyscyplina.id %}">\n                                        <span class="fi-print" style="color: palevioletred;"></span>\n                                    </a>\n                                {% endif %}\n                            </td>\n                        {% endif %}\n                    {% endif %}\n                </tr>\n            {% endfor %}\n        </table>\n        <h4>Punkty i sloty dyscyplin</h4>\n        <table>\n            <tr>\n                <th>Dyscyplina</th>\n                <th>PkD / PkDAut</th>\n                <th>Slot</th>\n            </tr>\n            {% for pd in rekord.punktacja_dyscypliny.select_related %}\n                <tr>\n                    <td>{{ pd.dyscyplina.nazwa }}</td>\n                    <td>{{ pd.pkd }}</td>\n                    <td>{{ pd.slot }}</td>\n                    {% load user_in_group %}\n                </tr>\n            {% endfor %}\n        </table>\n\n    {% endif %}\n{% endif %}\n\n<style type="text/css">\n/* BibTeX specific styles */\n#bibtex-container {\n    margin-top: 10px;\n}\n\n#bibtex-content {\n    width: 100%;\n    min-height: 200px;\n    font-family: 'Courier New', Consolas, Monaco, monospace;\n    font-size: 12px;\n    background-color: #f8f8f8;\n    border: 1px solid #ccc;\n    border-radius: 3px;\n    padding: 10px;\n    resize: vertical;\n    line-height: 1.4;\n}\n\n#bibtex-toggle-btn,\n#bibtex-copy-btn {\n    margin: 0;\n    vertical-align: top;\n}\n\n#bibtex-copy-btn {\n    margin-left: 10px;\n}\n\n#bibtex-copy-feedback {\n    margin-left: 10px;\n    color: #28a745;\n    font-weight: bold;\n    display: none;\n    vertical-align: top;\n}\n\n/* Responsive adjustments */\n@media screen and (max-width: 640px) {\n    #bibtex-content {\n        font-size: 10px;\n        min-height: 150px;\n    }\n\n    #bibtex-toggle-btn,\n    #bibtex-copy-btn {\n        font-size: 0.8rem;\n        padding: 0.5rem 1rem;\n    }\n}\n\n/* Better button styling for loading state */\n#bibtex-toggle-btn:disabled {\n    opacity: 0.6;\n    cursor: not-allowed;\n}\n</style>\n\n<script type="text/javascript">\n(function($) {\n    $(document).ready(function() {\n        var bibtexToggleBtn = $('#bibtex-toggle-btn');\n        var bibtexContainer = $('#bibtex-container');\n        var bibtexContent = $('#bibtex-content');\n        var bibtexCopyBtn = $('#bibtex-copy-btn');\n        var bibtexCopyFeedback = $('#bibtex-copy-feedback');\n        var bibtexLoaded = false;\n\n        // Toggle BibTeX display\n        bibtexToggleBtn.click(function() {\n            if (bibtexContainer.is(':visible')) {\n                bibtexContainer.hide();\n                bibtexToggleBtn.text('📋 Pokaż BibTeX');\n            } else {\n                if (!bibtexLoaded) {\n                    // Load BibTeX via AJAX\n                    loadBibTeX();\n                } else {\n                    bibtexContainer.show();\n                    bibtexToggleBtn.text('📋 Ukryj BibTeX');\n                }\n            }\n        });\n\n        // Copy to clipboard functionality\n        bibtexCopyBtn.click(function() {\n            copyToClipboard();\n        });\n\n        function loadBibTeX() {\n            bibtexToggleBtn.prop('disabled', true).text('⏳ Ładowanie...');\n\n            // Extract model and pk from the current page\n            var modelName = '{{ rekord.content_type.model }}';\n            var pk = '{{ praca.pk }}';\n\n            var url = '/bpp/api/bibtex/' + modelName + '/' + pk + '/';\n\n            $.ajax({\n                url: url,\n                type: 'GET',\n                dataType: 'json',\n                success: function(data) {\n                    bibtexContent.val(data.bibtex);\n                    bibtexContainer.show();\n                    bibtexToggleBtn.text('📋 Ukryj BibTeX');\n                    bibtexCopyBtn.show();\n                    bibtexLoaded = true;\n\n                    // Auto-resize textarea to content\n                    autoResizeTextarea();\n                },\n                error: function(xhr, status, error) {\n                    var errorMsg = 'Błąd podczas pobierania BibTeX';\n                    if (xhr.responseJSON && xhr.responseJSON.error) {\n                        errorMsg += ': ' + xhr.responseJSON.error;\n                    }\n                    bibtexContent.val(errorMsg);\n                    bibtexContainer.show();\n                    bibtexToggleBtn.text('📋 Ukryj BibTeX (błąd)');\n                },\n                complete: function() {\n                    bibtexToggleBtn.prop('disabled', false);\n                }\n            });\n        }\n\n        function autoResizeTextarea() {\n            var lines = bibtexContent.val().split('\\n').length;\n            var minHeight = 200;\n            var lineHeight = 16;\n            var newHeight = Math.max(minHeight, (lines + 1) * lineHeight);\n            bibtexContent.css('height', newHeight + 'px');\n        }\n\n        function copyToClipboard() {\n            // Modern Clipboard API\n            if (navigator.clipboard && window.isSecureContext) {\n                navigator.clipboard.writeText(bibtexContent.val()).then(function() {\n                    showCopyFeedback();\n                }, function(err) {\n                    fallbackCopy();\n                });\n            } else {\n                fallbackCopy();\n            }\n        }\n\n        function fallbackCopy() {\n            // Fallback for older browsers\n            bibtexContent.select();\n            bibtexContent[0].setSelectionRange(0, 99999); // For mobile devices\n\n            try {\n                document.execCommand('copy');\n                showCopyFeedback();\n            } catch (err) {\n                alert('Nie można skopiować do schowka. Proszę zaznacz tekst i skopiuj ręcznie (Ctrl+C).');\n            }\n        }\n\n        function showCopyFeedback() {\n            bibtexCopyFeedback.show();\n            setTimeout(function() {\n                bibtexCopyFeedback.fadeOut();\n            }, 2000);\n        }\n    });\n})(jQuery || django.jQuery || $);\n</script>\n\n{% if rekord.ma_odpiete_dyscypliny %}\n    {% if uczelnia.pokazuj_tabele_slotow_na_stronie_rekordu == "always" or uczelnia.pokazuj_tabele_slotow_na_stronie_rekordu == "logged-in" and not request.user.is_anonymous %}\n        <h4>"Odpięte" dyscypliny:</h4>\n        <table>\n            <tr>\n                <th>Autor</th>\n                <th>Dyscyplina</th>\n            </tr>\n            {% for pa in praca.odpiete_dyscypliny.select_related %}\n                <tr>\n                    <td>{{ pa.autor }}</td>\n                    <td>{{ pa.dyscyplina_naukowa.nazwa }}</td>\n                </tr>\n            {% endfor %}\n        </table>\n    {% endif %}\n{% endif %}\n	2000-01-01 00:00:00+00	2000-01-01 00:00:00+00
3	oswiadczenia/tresc_jednego_oswiadczenia.html	<h1>Oświadczenie upoważaniające podmiot do wykazania osiągnięć w ewaluacji jakości działalności naukowej</h1>\n<hr>\n<h2>{{ autor.nazwisko }} {{ autor.imiona }}</h2>\n<p>ORCID: <strong>{{ autor.orcid }}</strong></p>\n<p>Dyscypliny:</p>\n<ul>\n    <li>{{ dyscyplina_naukowa }}</li>\n    {% if subdyscyplina_naukowa %}\n        <li>{{ subdyscyplina_naukowa }}</li>\n    {% endif %}\n</ul>\n<p>\n    Ja, <strong>{{ autor.nazwisko }} {{ autor.imiona }}</strong>, zgodnie z art. 265 ust. 13 ustawy z dnia\n    20 lipca 2018 r. – Prawo  o szkolnictwie\n    wyższym i nauce (Dz. U. z 2021 r. poz. 478, z późn. zm.) upoważniam do wykazania na potrzeby\n    ewaluacji jakości działalności naukowej za lata <strong>2022-2025</strong> moich, wymienionych w niniejszym\n    oświadczeniu osiągnięć przez <strong>{{ uczelnia.nazwa }}</strong> w dyscyplinie:\n    <strong>{{ dyscyplina_pracy }}</strong>.\n</p>\n<p>\n    Oświadczam, że osiągnięcia te powstały w związku z prowadzeniem przeze mnie działalności naukowej\n    w tym podmiocie (nie dotyczy osiągnięć artystycznych).\n</p>\n<div width="10%" style="text-align: center; width:50%; float: right;">\n    <p>{{ data_oswiadczenia|default:"" }}...........................................................</p>\n    <p>(data i podpis)</p>\n</div>\n<div style="clear:both;"></div>\n<strong>Dotyczy:</strong><br/>\n{{ object.opis_bibliograficzny_cache|safe }}\n	2000-01-01 00:00:00+00	2000-01-01 00:00:00+00
\.


